Here's an example of how you could implement subquery detection in your existing relational algebra evaluator. This example assumes you're using Python and the `ast` module to parse the relational algebra expressions.

```python
import ast

class RelationalAlgebraEvaluator(ast.NodeVisitor):
    def __init__(self):
        self.subqueries = []

    def visit_Subscript(self, node):
        # Check if the subscript is a subquery
        if isinstance(node.value, ast.Name) and node.value.id == 'subquery':
            self.subqueries.append(node)
            return
        self.generic_visit(node)

    def visit_Call(self, node):
        # Check if the call is a subquery
        if isinstance(node.func, ast.Name) and node.func.id == 'subquery':
            self.subqueries.append(node)
            return
        self.generic_visit(node)

    def visit_BinOp(self, node):
        # Check if the binop is a subquery
        if isinstance(node.left, ast.Subscript) and node.left.value.id == 'subquery':
            self.subqueries.append(node.left)
            return
        if isinstance(node.right, ast.Subcript) and node.right.value.id == 'subquery':
            self.subqueries.append(node.right)

